+        counts = { IRNode.ADD_I, ">= 1", IRNode.REPLICATE_I, IRNode.VECTOR_SIZE_ANY, ">= 1" })
+    static int int_add(int ia, int ib) {
+        return IntVector.broadcast(ISP, ia)
